'use client';

import {
  Box, Button, Card, CardContent, TextField, Typography,
  InputAdornment, IconButton, FormControlLabel, Checkbox,
  Divider, Stack, Link
} from '@mui/material';
import { Visibility, VisibilityOff } from '@mui/icons-material';
import EmailIcon from '@mui/icons-material/Email';
import LockIcon from '@mui/icons-material/Lock';
import GoogleIcon from '@mui/icons-material/Google';
import AppleIcon from '@mui/icons-material/Apple';
import { useState } from 'react';
import { useRouter } from 'next/navigation';

export default function LoginPage() {
  const router = useRouter();
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleSignIn = () => {
    const correctUser = process.env.NEXT_PUBLIC_POS_USER || 'admin';
    const correctPass = process.env.NEXT_PUBLIC_POS_PASSWORD || '1234';
    if (email === correctUser && password === correctPass) {
      localStorage.setItem('auth_token', 'glossy-secret');
      router.push('/home');
    } else {
      alert('ชื่อผู้ใช้หรือรหัสผ่านไม่ถูกต้อง');
    }
  };

  return (
    <Box
      minHeight="100vh"
      display="flex"
      justifyContent="center"
      alignItems="center"
      bgcolor="#f5f5f5"
    >
      <Card sx={{ width: 380, borderRadius: 4, boxShadow: 4 }}>
        <CardContent>
          <Typography variant="h6" fontWeight="bold" gutterBottom>
            Email
          </Typography>
          <TextField
            placeholder="Enter your Email"
            fullWidth
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <EmailIcon />
                </InputAdornment>
              ),
            }}
          />

          <Typography variant="h6" fontWeight="bold" mt={3} gutterBottom>
            Password
          </Typography>
          <TextField
            placeholder="Enter your Password"
            type={showPassword ? 'text' : 'password'}
            fullWidth
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <LockIcon />
                </InputAdornment>
              ),
              endAdornment: (
                <InputAdornment position="end">
                  <IconButton onClick={() => setShowPassword((prev) => !prev)}>
                    {showPassword ? <VisibilityOff /> : <Visibility />}
                  </IconButton>
                </InputAdornment>
              ),
            }}
          />

          <Stack direction="row" justifyContent="space-between" alignItems="center" mt={1}>
            <FormControlLabel
              control={<Checkbox checked={rememberMe} onChange={(e) => setRememberMe(e.target.checked)} />}
              label="Remember me"
            />
            <Link href="#" underline="hover" fontSize="0.9rem">
              Forgot password?
            </Link>
          </Stack>

          <Button
            variant="contained"
            fullWidth
            sx={{
              mt: 2.5,
              py: 1.4,
              backgroundColor: '#000',
              fontWeight: 'bold',
              borderRadius: 2,
              textTransform: 'none',
              '&:hover': { backgroundColor: '#333' },
            }}
            onClick={handleSignIn}
          >
            Sign In
          </Button>

          <Stack direction="row" justifyContent="center" mt={2}>
            <Typography variant="body2">Don't have an account?</Typography>
            <Link href="#" ml={1} underline="hover" fontWeight="bold">
              Sign Up
            </Link>
          </Stack>

          <Divider sx={{ my: 3 }}>Or With</Divider>

          <Stack direction="row" spacing={2}>
            <Button
              fullWidth
              variant="outlined"
              startIcon={<GoogleIcon />}
              sx={{
                textTransform: 'none',
                fontWeight: 'bold',
                borderRadius: 2,
              }}
            >
              Google
            </Button>
            <Button
              fullWidth
              variant="outlined"
              startIcon={<AppleIcon />}
              sx={{
                textTransform: 'none',
                fontWeight: 'bold',
                borderRadius: 2,
              }}
            >
              Apple
            </Button>
          </Stack>
        </CardContent>
      </Card>
    </Box>
  );
}